+pub(crate) fn stub_broker_end_offset(topic: &str, partition: i32) -> i64 {
+    let state = stub_broker().state.lock();
+    state
+        .partitions
+        .get(&(topic.to_string(), partition))
+        .map_or(0, |partition_log| {
+            i64::try_from(partition_log.len()).unwrap_or(i64::MAX)
+        })
