+            .map_err(map_consumer_error)?
+            .to_topic_map()
+            .into_iter()
+            .filter_map(|(key, offset)| offset_from_rdkafka(offset).map(|offset| (key, offset)))
+            .collect()
+    };
+    Ok(broker_snapshot_from_topic_maps(
+        assigned_partitions,
+        positions,
+    ))
